import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.ArrayList;
import java.util.List;
import java.util.Optional;
import java.util.stream.Collectors;

public class Main {
    public static void main(String[] args) {
        if (args.length < 1) {
            System.err.println("Usage: java Main <source_directory>");
            System.exit(1);
        }

        String sourceDirectory = args[0];
        try {
            processDirectory(Paths.get(sourceDirectory));
        } catch (IOException e) {
            System.err.println("Error processing directory: " + e.getMessage());
            System.exit(1);
        }
    }

    private static void processDirectory(Path dir) throws IOException {
        Files.walk(dir)
                .filter(path -> path.toString().endsWith(".java"))
                .forEach(Main::processFile);
    }

    private static void processFile(Path filePath) {
        try {
            CompilationUnit cu = StaticJavaParser.parse(filePath.toFile());
            boolean modified = false;

            // Fix 1: Replace imports from redis.clients.jedis.commands package
            modified |= fixPipelineImports(cu);

            // Fix 2: Replace Client class reference
            modified |= fixClientClass(cu);

            // Fix 3: Fix Pipeline constructor calls
            modified |= fixPipelineConstructors(cu);

            if (modified) {
                cu.setStorage(filePath.toFile());
                cu.save();
                System.out.println("Modified: " + filePath);
            }
        } catch (Exception e) {
            System.err.println("Error processing " + filePath + ": " + e.getMessage());
        }
    }

    private static boolean fixPipelineImports(CompilationUnit cu) {
        boolean modified = false;
        List<ImportDeclaration> importsToRemove = new ArrayList<>();

        // Check for imports that need to be removed
        for (ImportDeclaration importDecl : cu.getImports()) {
            String importName = importDecl.getNameAsString();

            // Remove old pipeline imports from redis.clients.jedis.commands
            if (importName.startsWith("redis.clients.jedis.commands.")) {
                importsToRemove.add(importDecl);
                modified = true;
            }
        }

        // Remove the problematic imports
        for (ImportDeclaration importToRemove : importsToRemove) {
            cu.remove(importToRemove);
        }

        // Add new imports for the correct classes
        if (modified) {
            // Add the new imports that should be used instead
            NodeList<ImportDeclaration> newImports = new NodeList<>();
            newImports.add(new ImportDeclaration("redis.clients.jedis.Jedis", false, false));
            newImports.add(new ImportDeclaration("redis.clients.jedis.JedisCluster", false, false));
            newImports.add(new ImportDeclaration("redis.clients.jedis.Pipeline", false, false));
            newImports.add(new ImportDeclaration("redis.clients.jedis.MultiKeyPipeline", false, false));
            newImports.add(new ImportDeclaration("redis.clients.jedis.BinaryJedis", false, false));
            newImports.add(new ImportDeclaration("redis.clients.jedis.BinaryJedisCluster", false, false));
            newImports.add(new ImportDeclaration("redis.clients.jedis.ClusterPipeline", false, false));
            newImports.add(new ImportDeclaration("redis.clients.jedis.MultiKeyBinaryPipeline", false, false));
            newImports.add(new ImportDeclaration("redis.clients.jedis.MultiKeyCommandsPipeline", false, false));
            newImports.add(new ImportDeclaration("redis.clients.jedis.ScriptingCommandsPipeline", false, false));
            newImports.add(new ImportDeclaration("redis.clients.jedis.BinaryScriptingCommandsPipeline", false, false));
            newImports.add(new ImportDeclaration("redis.clients.jedis.BasicRedisPipeline", false, false));
            newImports.add(new ImportDeclaration("redis.clients.jedis.RedisPipeline", false, false));
            newImports.add(new ImportDeclaration("redis.clients.jedis.BinaryRedisPipeline", false, false));

            // Add the imports at the beginning of the imports list
            cu.getImports().addAll(0, newImports);
        }

        return modified;
    }

    private static boolean fixClientClass(CompilationUnit cu) {
        boolean modified = false;

        // Replace Client class references
        cu.findAll(ClassOrInterfaceType.class).forEach(type -> {
            if ("Client".equals(type.getNameAsString())) {
                // Check if it's from redis.clients.jedis package
                if (type.getScope().isPresent() && 
                    "redis.clients.jedis".equals(type.getScope().get().asString())) {
                    type.setName("Jedis");
                    modified = true;
                }
            }
        });

        // Replace Client constructor calls
        cu.findAll(ObjectCreationExpr.class).forEach(creation -> {
            if (creation.getType().isClassOrInterfaceExpr()) {
                ClassOrInterfaceType type = creation.getType().asClassOrInterfaceExpr();
                if ("Client".equals(type.getNameAsString())) {
                    if (type.getScope().isPresent() && 
                        "redis.clients.jedis".equals(type.getScope().get().asString())) {
                        type.setName("Jedis");
                        modified = true;
                    }
                }
            }
        });

        return modified;
    }

    private static boolean fixPipelineConstructors(CompilationUnit cu) {
        boolean modified = false;

        // Fix Pipeline constructor calls
        cu.findAll(ObjectCreationExpr.class).forEach(creation -> {
            if (creation.getType().isClassOrInterfaceExpr()) {
                ClassOrInterfaceType type = creation.getType().asClassOrInterfaceExpr();
                if ("Pipeline".equals(type.getNameAsString())) {
                    if (type.getScope().isPresent() && 
                        "redis.clients.jedis".equals(type.getScope().get().asString())) {
                        // Fix Pipeline constructor - it now requires a Jedis instance
                        List<Expression> arguments = creation.getArguments();
                        if (arguments.isEmpty()) {
                            // Add a default Jedis instance creation
                            arguments.add(new ObjectCreationExpr(
                                new ClassOrInterfaceType("Jedis"),
                                NodeList.nodeList()
                            ));
                            modified = true;
                        }
                    }
                }
            }
        });

        return modified;
    }
}

